var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"표정이 왜 그래, 레지나? 집에 돌아온 게 후회돼?","JPN":"どうかした？　レジーナ。家に帰ってきたこと、後悔してるの？","ENG":"Why the long face, Regina? Are you regretting coming back home?","TWN":"你怎麼這副表情，蕾佳娜？後悔回家了嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 후회는 하루에도 몇 번씩 했죠.","JPN":"後悔なんて一日何度もしていましたわ。","ENG":"That, I have regretted multiple times a day.","TWN":"這樣的後悔，每天在我的腦海中都要上演很多次。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지하실에서 먼지 쌓인 책장을 넘길 때도, 학회원들이 이해할 수 없는 짓을 일삼을 때도.","JPN":"地下室で埃が溜まった本をめくる時にも、学会員が訳のわからないことをする時にも。","ENG":"Whenever I flip through the dusty pages in the basement, or when the Society members do things I do not understand.","TWN":"在地下室弄倒堆滿灰塵的書架時，學會成員們做出那些讓我無法理解的事時。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그치. 앞으로도 틈만 나면 하게 될 거야.","JPN":"そうだね。これからも暇さえあれば後悔するようになるよ。","ENG":"Yeah. I bet you'll be doing it whenever you can in the future.","TWN":"好吧，那以後有空，你還是會後悔的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"하지만 자기가 불쌍하다고 착각하지만 마. 넌 이미 남들이 보기에 훌륭한 악당이거든.","JPN":"でも、間違っても自分がかわいそうだなんて思わないでよね。他の人から見たら立派な悪党なんだからさ。","ENG":"But don't think that you're pathetic. In the eyes of others, you're already an excellent villain.","TWN":"但是別以為自己很無辜。因為你已經是別人眼中的優秀壞人了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"How come?","TWN":"為什麼呢？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"이 지경까지 왔는데 학회를 없애 버리겠다는 발상은 절대 안 떠올리잖아.","JPN":"こんな状況になったのに、学会をなくすって発想はまったくないじゃん。","ENG":"You've come this far, but you haven't thought about getting rid of the Society, right?","TWN":"因為都已經到這種地步了，你也絕對沒想過要消滅學會不是嘛。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"보통은 한 놈이라도 더 많이 죽이고 싶어하는 게 정상이라구?","JPN":"一人でも多く殺したがるのが普通なのにさ。","ENG":"It's normal to want to kill more people, no?","TWN":"通常這種情況下，想要毀滅敵人才是正常的吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 사장님은 어째서 그런 부탁을 하셨을까요? 단순히 저와 같은 광인이라?","JPN":"だったら社長はどうしてそんなことを頼んだのでしょう？　単に私と同じ狂人だから？","ENG":"Then why would Boss make such a request? Simply because he is a lunatic like me?","TWN":"那老闆為什麼要說出那樣的請求呢？因為他是和我一樣的瘋子嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳은 어때요? 학회는 사라져야 한다고 생각하나요?","JPN":"リベットはどうですか？　学会はなくなるべきだと思いますか？","ENG":"What about you, Rivet? Do you also think that the Society should be abolished?","TWN":"里維是怎麼想的？你覺得學會必須消滅嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"당연하지. 난 너도 나도 인정하는 상식인이잖아.","JPN":"当たり前じゃん。アタシは、アンタもアタシも認める常識人だからね。","ENG":"Without a doubt. I'm a rational person, and we both admit that's true.","TWN":"當然。因為我是公認的正常人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"없애지 말아야 할 이유를 찾아야겠네요. 당신이 찬성할 정도라면.","JPN":"なくしてはいけない理由を探さなければいけませんね。あなたが賛成するくらいなら。","ENG":"Then, I need to find a reason not to. Since even you agree with that.","TWN":"那我得找到不該消滅學會的理由了呢。如果這件事連你都贊成的話。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"우우, 폭군이다. 제멋대로에 성격도 나쁜 폭군.","JPN":"うう～暴君だ～自分勝手で性格も悪い暴君。","ENG":"Ooh, a tyrant. A bad tyrant with an even worse personality.","TWN":"嗚嗚，暴君，任性妄為、性格差勁的暴君。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시라도 다시 만나게 되면, 한 가지 물어 보고 싶었어요.","JPN":"もしまた会えたら、一つだけ聞きたかったことがあります。","ENG":"I wanted to ask you something if we were to ever meet again.","TWN":"如果能再見到你，我一直有一個問題想問你。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 시설에서 저를 데리고 도망쳤죠?","JPN":"どうして施設から私を連れて逃げたのですか？","ENG":"Why did you take me with you when you ran away from that facility?","TWN":"在設施裡，你為什麼帶著我逃走了？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 미치광이라도 에델과 척을 지는 짓이라는 걸 모르진 않았을 텐데요.","JPN":"いくら狂人でも、エデルに敵対することだと知っていたはずですのに。","ENG":"Even if you are insane, you knew not to make Edel your enemy.","TWN":"就算你是個瘋子，也應該知道這麼做會跟艾瑟兒結仇吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"사실 내가 네 진짜 엄마란다.","JPN":"実は、アタシがアンタの本当のお母さんなんだ。","ENG":"Well. I am your Mother.","TWN":"因為我才是你真正的媽媽。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 입 꽁꽁 얼려 버리기 전에 대답해요.","JPN":"その口を凍らせてしまう前に、答えなさい。","ENG":"Answer me before I freeze your lips together forever.","TWN":"在我把你那張嘴結凍上之前，請你好好回答。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그치만 이유 같은 거 딱히 없는걸?","JPN":"でも、理由なんか別にないもんな～。","ENG":"But there really is no reason at all.","TWN":"但就是沒有什麼特別的理由啊？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"난 <color=#ffd34c>그냥</color> 원래 그런 사람이야. 상식적이고 조신한.","JPN":"アタシは<color=#ffd34c>ただ</color>元々そんな人間なんだ。常識的で、つつましい。","ENG":"I'm <color=#ffd34c>just</color> that kinda gal. Rational and cautious.","TWN":"我<color=#ffd34c>本來就是</color>那種人啊。文靜、有常識的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그러니까 레지나도 자기가 괴팍하고 악랄하다는 사실을 받아들이라고.","JPN":"だから、レジーナも自分が偏屈であくどいっていう事実を受け入れなよ。","ENG":"So why don't you accept the fact that you're weird and wicked too?","TWN":"所以，蕾佳娜也接受自己古怪惡毒的事實吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 당신은 그냥 몰상식하고 제멋대로인 여자예요.","JPN":"いいえ。あなたはただ非常識で自分勝手な女ですわ。","ENG":"No. You are just an irrational, self-indulgent girl.","TWN":"不，你就是一個無知又任性妄為的女人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에이, 날 너무 깊이 아는 고용주는 싫은데.","JPN":"ええ～、アタシのことに詳しい雇い主はイヤだなあ。","ENG":"Aw c'mon. You know I don't like it when my clients know me too well.","TWN":"欸，我不喜歡過於了解我的雇主。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래서 말인데, 이제 어떡할래?","JPN":"それでだけど、これからどうする？","ENG":"So anyway, what's your next move?","TWN":"所以說，現在要怎麼辦？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"예복으로 갈아 입고 찾아간다고 에델이 갑자기 마음을 바꿔 먹을 것 같진 않은데.","JPN":"礼服に着替えて会いに行ったって、エデルが急に心を変えるはずないと思うよ。","ENG":"It's not like Edel's going to suddenly change her mind when you show up wearing that dress, right?","TWN":"就算我換上禮服去找艾瑟兒，她也不會突然改變主意的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 당신은 왜 음식을 가지고 다녔죠?","JPN":"リベット、あなたはどうして食べ物を持ち歩いていたのですか？","ENG":"Rivet, why do you carry around food with you?","TWN":"里維，你為什麼隨身帶著食物？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그야 배고프면 기회가 생겨도 못 날뛰니까?","JPN":"そりゃあ、お腹が空いてたらチャンスがきても暴れられないから？","ENG":"Well, I can't run wild if I'm hungry, right?","TWN":"那是因為如果肚子餓的話，哪怕有機會放縱自己？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"보존식도 음식으로 쳐 준다면 말이야. 그건 왜?","JPN":"保存食も食べ物扱いしてくれるならね。それがなに？","ENG":"Even if it's preserved food, it's still food. Why do you ask?","TWN":"如果冷凍食品也算食物的話，怎麼了？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"우리가 음식을 섭취하듯이, 정보 집합체인 에델도 정보를 섭취해야 해요.","JPN":"私たちが食べ物を摂取するように、情報の集合体であるエデルも情報を摂取しないといけません。","ENG":"Just like we consume food, a massive collection of information, Edel, needs to consume information.","TWN":"就像我們需要攝取食物一樣，資訊集合體艾瑟兒也需要攝取資訊。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만…… 식사하는 방식을 감안하면, 우리와 결정적으로 다른 점이 있을지도 몰라요.","JPN":"ですが……食事方法を考えると、私たちとは決定的な相違点があるかもしれませんわ。","ENG":"But... I believe that her method of consumption is ultimately different from how we eat.","TWN":"但是……她用餐的方式，或許和我們有著決定性的不同。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래? 예를 들면 뭔데?","JPN":"ふうん？　例えば？","ENG":"Really? Could you give me an example?","TWN":"是嗎？譬如說什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아직은 도박 같은 가설에 불과해요. 그걸 검증하러 갈 생각입니다.","JPN":"まだ賭けに近い仮説に過ぎません。それを検証しに行くつもりです。","ENG":"This is all still just a hypothesis, but I am going to test it out.","TWN":"現在還只是如賭博般的假設。我打算去驗證一下。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"채비를 갖추려면 시간이 필요해요.","JPN":"準備をする時間が必要です。","ENG":"I will need time to prepare.","TWN":"我需要一些時間來準備。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 부탁해도 될까요?","JPN":"リベット、お願いしてもいいですか？","ENG":"Rivet, may I ask you a favor?","TWN":"里維，能請你幫個忙嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"물론이지. 폭탄도 잔뜩 써도 돼?","JPN":"もちろんだよ。爆弾、いっぱい使っていい？","ENG":"Sure! Can I use a lot of bombs?","TWN":"當然。我可以用很多炸彈嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"밖에서 총소리가 끊이지 않아요. 외지인님이 열심히 싸우고 계신가 봐요.","JPN":"外で銃声が絶えませんね。よそ者様が頑張って戦ってくださっているみたいです。","ENG":"The gunshots outside never seem to stop. That must mean Ms. Rivet is putting up a good fight.","TWN":"外面槍聲不斷。外地人好像在努力戰鬥。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"이 틈에 몸을 피하시면 어떨까요?","JPN":"この隙に避難してはどうでしょうか？","ENG":"Shouldn't we use this opportunity to run away?","TWN":"趁這個時候，你躲起來怎麼樣？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"오래된 저택이니까 비밀 통로가 있을지도 몰라요. 저와 함께 찾아 봐요, 부학회장님.","JPN":"古い邸宅ですから、秘密通路があるかもしれません。探してみましょう、副学会長様。","ENG":"It's an old mansion, so there might be a hidden passageway somewhere. Let's try to find one, ma'am.","TWN":"因為是老屋，裡面說不定會有秘密通道。你和我一起找找吧，副學會長。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 저택은 저희 가문의 것입니다. 여기서는 단 한 발짝도 물러설 수 없어요.","JPN":"この邸宅は我が家門のものです。ここからは一歩も引けません。","ENG":"This mansion belongs to my family. I will not back down from here.","TWN":"這個宅邸是我們家族的。在這裡，我不能後退半步。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만……","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니까 저는 힘을 되찾을 거예요, 실키.","JPN":"ですから私は力を取り戻すことにします、シルキー。","ENG":"I am going to get my powers back, Sylkie.","TWN":"所以，我會找回我的力量，思琪。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"맞아요. 능력을 제대로 쓸 수 없다고 하셨죠….","JPN":"そうでした。能力をまともに使えないとおっしゃってましたね……","ENG":"Oh, right. You said that you couldn't use your powers...","TWN":"沒錯，你說過你的能力不好用了……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"되찾을 방법이 있을까요?","JPN":"取り戻す方法があるのですか？","ENG":"Have you found a way to get them back?","TWN":"你有辦法找回來嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 있습니다.","JPN":"はい。あります。","ENG":"Yes, I have.","TWN":"是的，我有辦法。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"오히려 줄곧……. 제가 되찾기만을 기다리고 있었을 거예요.","JPN":"むしろずっと……私が取り戻すことを待っていたはずなのです。","ENG":"After all this time... it has been waiting for me to retrieve it.","TWN":"相反……它應該一直在等著我找回吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};